BEGIN; DO $$ DECLARE v_signature regprocedure := to_regprocedure('public.shipment_outbound_delivery(jsonb,uuid,uuid,uuid,text,text,text,text,text,date,uuid)'); v_definition text; v_updated text; BEGIN IF v_signature IS NULL THEN RAISE EXCEPTION 'Khong tim thay ham shipment_outbound_delivery dung chu ky.'; END IF; SELECT pg_get_functiondef(v_signature) INTO v_definition; v_updated := replace(v_definition, 'v_shipment_no := v_existing_shipment.shipment_no;', E'v_shipment_no := v_existing_shipment.shipment_no;\n    v_driver_1 := v_existing_shipment.driver_1_name_snapshot;'); IF v_updated = v_definition THEN RAISE EXCEPTION 'Khong tim thay nhanh ghep chuyen de cap nhat tai xe.'; END IF; v_definition := v_updated; v_updated := replace(v_definition, '''Chuyen '' || v_shipment_no || COALESCE('' - '' || p_note, '''')', '''Xe '' || COALESCE(NULLIF(btrim(v_driver_1), ''''), ''Chua co tai xe'') || '' - '' || v_shipment_no'); IF v_updated = v_definition THEN RAISE EXCEPTION 'Khong tim thay mau ghi chu cu; dung migration de tranh sua nham ham live.'; END IF; EXECUTE v_updated; END $$; NOTIFY pgrst, 'reload schema'; COMMIT;
